mapper.select:
SELECT ct.*, pr.company_name AS promoter_company_name, p.title AS performance_title FROM coupon_template ct LEFT JOIN promoter pr ON ct.promoter_id = pr.promoter_id LEFT JOIN performance p ON ct.performance_id = p.performance_id
AND ct.promoter_id = #{promoterId} AND ct.is_active = #{isActive}
ORDER BY ct.created_at DESC

mapper.update:
UPDATE coupon
SET status = 'USED', used_at = NOW(), reservation_id = #{reservationId}
WHERE coupon_code = #{couponCode} AND status = 'ISSUED' AND expires_at > NOW()
